        public CustomPermission(string permissionName, bool isGranted)
        {
            PermissionName = permissionName;
            IsGranted = isGranted;
        }
        
        public bool HasAccess(string resource)
        {
            // Simple dummy check: if permission is granted and resource name starts with permission name.
            return IsGranted && resource.StartsWith(PermissionName, StringComparison.OrdinalIgnoreCase);
        }
